// frontend/src/App.js
import React from 'react';
import { Routes, Route } from 'react-router-dom';
import Layout from './components/Layout';
import ProtectedRoute from './components/ProtectedRoute';

// Pages
import SplashPage      from './pages/SplashPage';
import HomePage        from './pages/HomePage';
import AboutPage       from './pages/AboutPage';
import ContactPage     from './pages/ContactPage';
import LoginPage       from './pages/LoginPage';
import RegisterPage    from './pages/RegisterPage';
import PostPage        from './pages/PostPage';
import ProfilePage     from './pages/ProfilePage';
import CreatePostPage  from './pages/CreatePostPage';
import EditPostPage    from './pages/EditPostPage';
import AdminPage       from './pages/AdminPage';

import './App.css';

function App() {
  return (
    <Routes>

      {/* ── Splash — NO Layout, NO scroll (handled in SplashPage.css) ── */}
      <Route path="/" element={<SplashPage />} />

      {/* ── Public routes — wrapped in Layout, body is scrollable ── */}
      <Route path="/home"      element={<Layout><HomePage /></Layout>} />
      <Route path="/about"     element={<Layout><AboutPage /></Layout>} />
      <Route path="/contact"   element={<Layout><ContactPage /></Layout>} />
      <Route path="/login"     element={<Layout><LoginPage /></Layout>} />
      <Route path="/register"  element={<Layout><RegisterPage /></Layout>} />
      <Route path="/posts/:id" element={<Layout><PostPage /></Layout>} />

      {/* ── Protected — must be logged in ── */}
      <Route path="/profile" element={
        <ProtectedRoute>
          <Layout><ProfilePage /></Layout>
        </ProtectedRoute>
      } />
      <Route path="/create-post" element={
        <ProtectedRoute>
          <Layout><CreatePostPage /></Layout>
        </ProtectedRoute>
      } />
      <Route path="/edit-post/:id" element={
        <ProtectedRoute>
          <Layout><EditPostPage /></Layout>
        </ProtectedRoute>
      } />

      {/* ── Admin only ── */}
      <Route path="/admin" element={
        <ProtectedRoute role="admin">
          <Layout><AdminPage /></Layout>
        </ProtectedRoute>
      } />

    </Routes>
  );
}

export default App;
